@js:
var doc = org.jsoup.Jsoup.parse(result);
var playBox = doc.select(".detail-anime-play").first();

if (playBox == null) {
    "未获取到播放列表";
} else {
    function cleanText(str) {
        return String(str || "").replace(/\s+/g, "").trim();
    }

    function fullUrl(href) {
        href = String(href || "").trim().replace(/\s+/g, "");
        if (href.indexOf("http") == 0) return href;
        if (href.indexOf("//") == 0) return "https:" + href;
        if (href.indexOf("/") == 0) return "https://acgfta.com" + href;
        return "https://acgfta.com/" + href;
    }

    function esc(str) {
        return String(str || "")
            .replace(/&/g, "&amp;")
            .replace(/</g, "&lt;")
            .replace(/>/g, "&gt;")
            .replace(/"/g, "&quot;")
            .replace(/'/g, "&#39;");
    }

    function jsEsc(str) {
        return String(str || "")
            .replace(/\\/g, "\\\\")
            .replace(/'/g, "\\'")
            .replace(/"/g, "\\\"")
            .replace(/\n/g, "")
            .replace(/\r/g, "");
    }

    var lines = playBox.select(".anime-episode");
    var firstUrl = "";

    for (var i = 0; i < lines.size(); i++) {
        var firstEp = lines.get(i).select("a.btn-episode").first();
        if (firstEp != null) {
            firstUrl = fullUrl(firstEp.attr("href"));
            break;
        }
    }

    var html = "";

    html += "<style>";
    html += "*{box-sizing:border-box;}";
    html += ".play-wrap{padding:10px;background:#f5f6fa;border-radius:16px;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;}";
    html += ".player-box{position:relative;width:100%;aspect-ratio:16/9;background:#000;border-radius:16px;overflow:hidden;margin-bottom:12px;box-shadow:0 8px 22px rgba(0,0,0,.25);}";
    html += ".player-box video{width:100%;height:100%;background:#000;display:block;}";
    html += ".player-loading{position:absolute;left:0;top:0;width:100%;height:100%;display:flex;align-items:center;justify-content:center;color:#ddd;background:#000;font-size:14px;z-index:2;}";
    html += ".line-tabs{display:flex;gap:8px;overflow-x:auto;padding:2px 0 10px;margin:0 0 8px;}";
    html += ".line-tabs button{flex:0 0 auto;border:none;padding:8px 14px;border-radius:999px;background:#eef2ff;color:#374151;font-size:14px;font-weight:700;}";
    html += ".line-tabs button.active{background:#4f8cff;color:#fff;box-shadow:0 5px 14px rgba(79,140,255,.32);}";
    html += ".line-panel{display:none;}";
    html += ".line-panel.active{display:block;}";
    html += ".episode-box{display:grid;grid-template-columns:repeat(4,1fr);gap:9px;}";
    html += ".episode-box button{width:100%;padding:10px 6px;text-align:center;background:#fff;color:#222;border-radius:12px;border:1px solid #e5e7eb;font-size:14px;font-weight:650;box-shadow:0 2px 8px rgba(0,0,0,.05);position:relative;}";
    html += ".episode-box button.active{background:#4f8cff;color:#fff;border-color:#4f8cff;}";
    html += ".episode-box button.watched{background:#dbeafe;border-color:#93c5fd;}";
    html += ".episode-box button:active{transform:scale(.97);}";
    html += "@media(max-width:360px){.episode-box{grid-template-columns:repeat(3,1fr);}}";
    html += ".history-bar{display:flex;justify-content:flex-end;padding:4px 0;}";
    html += ".history-bar button{background:transparent;border:1px solid #d1d5db;padding:4px 10px;border-radius:6px;font-size:12px;color:#6b7280;}";
    html += "</style>";

    html += "<div class='play-wrap'>";

    html += "<div id='playerBox' class='player-box'>";
    html += "<div id='playerLoading' class='player-loading'>加载中...</div>";
    html += "<video id='videoPlayer' controls playsinline webkit-playsinline x5-playsinline preload='auto'></video>";
    html += "</div>";

    html += "<div class='line-tabs'>";

    for (var t = 0; t < lines.size(); t++) {
        var tabName = String(lines.get(t).attr("id") || "").trim();
        if (tabName.length == 0) tabName = "线路" + (t + 1);
        html += "<button type='button' id='tab_" + t + "' class='" + (t == 0 ? "active" : "") + "' onclick='showLine(" + t + ")'>" + esc(tabName) + "</button>";
    }

    html += "</div>";

    for (var x = 0; x < lines.size(); x++) {
        var line = lines.get(x);
        html += "<div id='panel_" + x + "' class='line-panel " + (x == 0 ? "active" : "") + "'>";
        html += "<div class='episode-box'>";

        var episodes = line.select("a.btn-episode");

        for (var j = 0; j < episodes.size(); j++) {
            var ep = episodes.get(j);
            var title = cleanText(ep.text());
            var url = fullUrl(ep.attr("href"));
            html += "<button type='button' id='ep_" + x + "_" + j + "' data-url='" + jsEsc(url) + "' onclick=\"changePlay('" + jsEsc(url) + "','ep_" + x + "_" + j + "')\">" + esc(title) + "</button>";
        }

        html += "</div>";
        html += "</div>";
    }

    // 添加清除历史按钮（可选）
    html += "<div class='history-bar'>";
    html += "<button onclick='clearHistory()'>🗑 清除历史</button>";
    html += "</div>";

    html += "</div>";

    html += "<script>";
    html += "var firstPlayUrl='" + jsEsc(firstUrl) + "';";
    html += "var currentLine=0, currentIdx=0, currentTitle='';";

    // 历史记录核心
    html += "var STORAGE_KEY='acgfta_history';";
    html += "function getHistory(){try{var d=localStorage.getItem(STORAGE_KEY);return d?JSON.parse(d):{};}catch(e){return{};}}";
    html += "function saveHistory(){";
    html += "var h={line:currentLine, index:currentIdx, title:currentTitle, time:0};";
    html += "var video=document.getElementById('videoPlayer');";
    html += "if(video)h.time=video.currentTime||0;";
    html += "try{localStorage.setItem(STORAGE_KEY,JSON.stringify(h));}catch(e){}";
    html += "}";
    html += "function clearHistory(){";
    html += "localStorage.removeItem(STORAGE_KEY);";
    html += "alert('历史记录已清除');";
    html += "}";

    // 标记已看集数
    html += "function markWatched(id){";
    html += "var btn=document.getElementById(id);";
    html += "if(btn&&!btn.classList.contains('watched')){";
    html += "btn.classList.add('watched');";
    html += "}";
    html += "}";

    // 基础切换函数
    html += "function showLine(index){";
    html += "var tabs=document.querySelectorAll('.line-tabs button');";
    html += "var panels=document.querySelectorAll('.line-panel');";
    html += "for(var i=0;i<tabs.length;i++){tabs[i].classList.remove('active');}";
    html += "for(var j=0;j<panels.length;j++){panels[j].classList.remove('active');}";
    html += "document.getElementById('tab_'+index).classList.add('active');";
    html += "document.getElementById('panel_'+index).classList.add('active');";
    html += "}";

    html += "function setActive(id){";
    html += "var eps=document.querySelectorAll('.episode-box button');";
    html += "for(var i=0;i<eps.length;i++){eps[i].classList.remove('active');}";
    html += "var now=document.getElementById(id);";
    html += "if(now){now.classList.add('active');markWatched(id);}";
    html += "}";

    // 强大的 m3u8 提取器
    html += "function getM3u8FromText(txt){";
    html += "var m=txt.match(/var\\s+player_aaaa\\s*=\\s*(\\{[\\s\\S]*?\\})<\\/script>/);";
    html += "if(!m){m=txt.match(/var\\s+player_aaaa\\s*=\\s*(\\{[\\s\\S]*?\\})/);}";
    html += "if(m){";
    html += "try{";
    html += "var obj=JSON.parse(m[1]);";
    html += "if(obj&&obj.url)return obj.url;";
    html += "}catch(e){";
    html += "var u=m[1].match(/\"url\"\\s*:\\s*\"([^\"]+)\"/);";
    html += "if(u)return u[1].replace(/\\\\\\//g,'/');";
    html += "}";
    html += "}";
    // 尝试匹配 __NUXT__ 状态
    html += "var nuxt=txt.match(/__NUXT__\\s*=\\s*(\\{[\\s\\S]*?\\});?\\s*<\\/script>/);";
    html += "if(nuxt){";
    html += "try{";
    html += "var data=JSON.parse(nuxt[1]);";
    html += "var state=data.state||data;";
    html += "if(state.player_aaaa&&state.player_aaaa.url)return state.player_aaaa.url;";
    html += "}catch(e){}";
    html += "}";
    // 直接匹配 .m3u8 链接
    html += "var direct=txt.match(/https?:\\/\\/[^\\s\"']+\\.m3u8[^\\s\"']*/i);";
    html += "return direct ? direct[0] : '';";
    html += "}";

    html += "function playM3u8(m3u8){";
    html += "var video=document.getElementById('videoPlayer');";
    html += "var loading=document.getElementById('playerLoading');";
    html += "if(!m3u8){loading.innerHTML='未获取到播放地址';return;}";
    html += "loading.style.display='none';";
    html += "video.src=m3u8;";
    html += "video.load();";
    html += "video.play().catch(function(){});";
    html += "}";

    html += "function changePlay(playUrl,id){";
    html += "setActive(id);";
    html += "var parts=id.split('_');";
    html += "if(parts.length===3){";
    html += "  currentLine=parseInt(parts[1]);";
    html += "  currentIdx=parseInt(parts[2]);";
    html += "}";
    html += "var btn=document.getElementById(id);";
    html += "currentTitle=btn?btn.innerText.trim():'';";
    html += "var loading=document.getElementById('playerLoading');";
    html += "loading.style.display='flex';";
    html += "loading.innerHTML='加载中...';";
    // 请求时带上 Referer，避免跨域屏蔽
    html += "fetch(playUrl, {headers: {'Referer': 'https://acgfta.com/'}}).then(function(res){return res.text();}).then(function(txt){";
    html += "var m3u8=getM3u8FromText(txt);";
    html += "playM3u8(m3u8);";
    html += "saveHistory();";
    html += "}).catch(function(err){";
    html += "loading.innerHTML='请求失败：'+err.message;";
    html += "});";
    html += "window.scrollTo(0,0);";
    html += "}";

    // 自动保存播放进度
    html += "var video=document.getElementById('videoPlayer');";
    html += "video.addEventListener('timeupdate',function(){";
    html += "if(video.currentTime) saveHistory();";
    html += "});";

    // 尝试恢复历史
    html += "function restoreHistory(){";
    html += "var h=getHistory();";
    html += "if(!h.line && h.line!==0)return false;";
    html += "showLine(h.line);";
    html += "var histId='ep_'+h.line+'_'+h.index;";
    html += "var btn=document.getElementById(histId);";
    html += "if(btn){";
    html += "  changePlay(btn.getAttribute('data-url'), histId);";
    html += "  var vid=document.getElementById('videoPlayer');";
    html += "  if(h.time && vid){";
    html += "    vid.addEventListener('loadedmetadata',function(){";
    html += "      this.currentTime=h.time;";
    html += "    }, {once: true});";
    html += "  }";
    html += "  return true;";
    html += "}";
    html += "return false;";
    html += "}";

    // 启动播放（优先历史，否则播第一集）
    html += "setTimeout(function(){";
    html += "  if(!restoreHistory()) changePlay(firstPlayUrl,'ep_0_0');";
    html += "}, 100);";
    html += "</script>";

    html;
}

